Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/WhoFailedToLodgeQuestionnaireList/WhoFailedToLodgeQuestionnaire[./Value = " + WhoFailedToLodgeQuestionnaire.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/WhoFailedToLodgeQuestionnaireList/WhoFailedToLodgeQuestionnaire[./Description = " + WhoFailedToLodgeQuestionnaire.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

